237→/**
238→ * Navigates a dot-path (e.g. "academics.enrollment") into a SearchInstitution
239→ * and returns the leaf value. Returns undefined if any segment is missing.
240→ */
241→export function getFieldValue(
242→  inst: SearchInstitution,
243→  outputKey: string | null | undefined,
244→): unknown {
245→  if (!outputKey) return undefined
246→  const parts = outputKey.split('.')
247→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
248→  let current: any = inst
249→  for (const part of parts) {
250→    if (current == null || typeof current !== 'object') return undefined
251→    current = current[part]
252→  }
253→  return current ?? undefined
254→}
