285→export function formatCellValue(value: unknown, unit?: SearchFieldUnit | null): string {
286→  if (value === null || value === undefined || value === '') return '—'
287→  const num = Number(value)
288→  if (unit === 'DOLLARS' && !isNaN(num)) {
289→    return `$${Math.round(num).toLocaleString()}`
290→  }
291→  if (unit === 'PERCENTAGE' && !isNaN(num)) {
292→    return `${(num * 100).toFixed(1)}%`
293→  }
294→  if (unit === 'MILES' && !isNaN(num)) {
295→    return `${num.toLocaleString()} mi`
296→  }
297→  return String(value)
298→}
